// Function to compute base^exp safely with early stop
long long power(int base, int exp, int limit) {
    long long result = 1;
    for (int i = 0; i < exp; i++) {
        result *= base;
        if (result > limit) return result; // stop early if it exceeds limit
    }
    return result;
}

// Function to find Nth root of M
int nthRoot(int n, int m) {
    int low = 1, high = m;
    while (low <= high) {
        int mid = low + (high - low) / 2;
        long long val = power(mid, n, m);

        if (val == m) return mid;     // found exact root
        if (val < m) low = mid + 1;  // search higher
        else high = mid - 1;         // search lower
    }
    return -1; // no integer root
}

