// Function to compute base^exp safely with early stop
function power(base, exp, limit) {
    let result = 1n; // use BigInt for safety
    let b = BigInt(base);
    let l = BigInt(limit);

    for (let i = 0; i < exp; i++) {
        result *= b;
        if (result > l) return result;
    }
    return result;
}

// Function to find Nth root of M
function nthRoot(n, m) {
    let low = 1, high = m;
    let target = BigInt(m);

    while (low <= high) {
        let mid = Math.floor((low + high) / 2);
        let val = power(mid, n, m);

        if (val === target) return mid;
        if (val < target) low = mid + 1;
        else high = mid - 1;
    }
    return -1;
}
